// Collection A wrapped collection as returned by GET endpoints. The mutable payload
// lives in `data`; the outer object carries library, links, and
// computed meta (numItems, numCollections).
type Collection struct {
	// Data The mutable collection payload. Used in `POST /collections` (create
	// or batch-update) and `PATCH /collections/{collectionKey}`.
	//
	// For **creates**: supply `name` (and optionally `parentCollection`);
	// omit `key` and `version`.
	// For **updates**: include `key` + `version` and the fields to change.
	Data                 CollectionData          `json:"data"`
	Key                  string                  `json:"key"`
	Library              LibraryRef              `json:"library"`
	Links                *map[string]interface{} `json:"links,omitempty"`
	Meta                 *Collection_Meta        `json:"meta,omitempty"`
	Version              int                     `json:"version"`
	AdditionalProperties map[string]interface{}  `json:"-"`
}

// Collection_Meta defines model for Collection.Meta.
type Collection_Meta struct {
	// NumCollections Number of sub-collections under this collection.
	NumCollections *int `json:"numCollections,omitempty"`

	// NumItems Number of items directly in this collection.
	NumItems             *int                   `json:"numItems,omitempty"`
	AdditionalProperties map[string]interface{} `json:"-"`
}

// CollectionData The mutable collection payload. Used in `POST /collections` (create
// or batch-update) and `PATCH /collections/{collectionKey}`.
//
// For **creates**: supply `name` (and optionally `parentCollection`);
// omit `key` and `version`.
// For **updates**: include `key` + `version` and the fields to change.
type CollectionData struct {
	// Key Present on updates; omit on creates.
	Key *string `json:"key,omitempty"`

	// Name Collection display name.
	Name string `json:"name"`

	// ParentCollection Parent collection key for nested collections, or `false` to make
	// this a top-level collection.
	ParentCollection *CollectionData_ParentCollection `json:"parentCollection,omitempty"`

	// Relations Related-collection relations (predicate → object URIs).
	Relations *map[string]interface{} `json:"relations,omitempty"`

	// Version Present on updates; omit on creates.
	Version              *int                   `json:"version,omitempty"`
	AdditionalProperties map[string]interface{} `json:"-"`
}

// CollectionDataParentCollection0 defines model for .
type CollectionDataParentCollection0 = string

// CollectionDataParentCollection1 defines model for CollectionData.ParentCollection.1.
type CollectionDataParentCollection1 bool

// CollectionData_ParentCollection Parent collection key for nested collections, or `false` to make
// this a top-level collection.
type CollectionData_ParentCollection struct {
	union json.RawMessage
}

// Creator Either a two-name creator (`firstName`+`lastName`) or a single-name
// creator (`name`).
type Creator struct {
	// CreatorType Role of the creator (author, editor, translator, etc.).
	CreatorType string  `json:"creatorType"`
	FirstName   *string `json:"firstName,omitempty"`
	LastName    *string `json:"lastName,omitempty"`

	// Name Used instead of firstName/lastName for institutional creators.
	Name *string `json:"name,omitempty"`
}

// DeletedContent Tombstone feed for incremental sync. Each field is the list of
// identifiers of objects of that type that were deleted since the
// client's last known library version.
type DeletedContent struct {
	// Collections Keys of collections deleted since `since`.
	Collections []string `json:"collections"`

	// Items Keys of items deleted since `since`.
	Items []string `json:"items"`

	// Searches Keys of saved searches deleted since `since`.
	Searches []string `json:"searches"`

	// Settings Keys of settings removed since `since` (e.g. `tagColors`,
	// `feeds`). Included for completeness — this spec does not
	// currently model the `/settings` read/write surface.
	Settings []string `json:"settings"`

	// Tags Names of tags removed from the library since `since`. Tags
	// are identified by name, not by key.
	Tags []string `json:"tags"`
}

// Fulltext Indexed fulltext content for an attachment.
type Fulltext struct {
	// Content The extracted plain-text content.
	Content string `json:"content"`

	// IndexedChars Number of characters indexed.
	IndexedChars *int `json:"indexedChars,omitempty"`

	// IndexedPages Number of pages indexed (PDFs only).
	IndexedPages *int `json:"indexedPages,omitempty"`

	// TotalChars Total characters in the original document.
	TotalChars *int `json:"totalChars,omitempty"`

	// TotalPages Total pages in the original document (PDFs only).
	TotalPages           *int                   `json:"totalPages,omitempty"`
	AdditionalProperties map[string]interface{} `json:"-"`
}

// FulltextVersions Map of `itemKey` to the current fulltext version for items whose
// indexed fulltext content changed since the caller's `since`
// version. An empty object means no fulltext changed in that
// window.
type FulltextVersions map[string]int

