// Item A wrapped item as returned by GET endpoints. The bibliographic payload
// lives in `data`; the outer object carries library, links, and meta info.
type Item struct {
	// Data The mutable item payload. This is what you send in `POST /items`
	// (for both create and update) and `PATCH /items/{itemKey}`.
	//
	// For **creates**: omit `key` and `version`; the server assigns them.
	// For **updates**: include `key` and `version` (PATCH semantics —
	// only send the fields you want to change).
	//
	// Fields below are the common bibliographic fields plus the major
	// `journalArticle` and `attachment` fields. The API accepts many more
	// fields depending on `itemType` (see `/schema`); `additionalProperties`
	// is permissive to allow them.
	Data ItemData `json:"data"`

	// Key 8-character unique item key within the library.
	Key     string     `json:"key"`
	Library LibraryRef `json:"library"`

	// Links HATEOAS links (self, alternate, up, attachment).
	Links *map[string]interface{} `json:"links,omitempty"`

	// Meta Computed metadata (creator summary, numChildren, parsed date).
	Meta *Item_Meta `json:"meta,omitempty"`

	// Version Object version number (monotonic per library).
	Version              int                    `json:"version"`
	AdditionalProperties map[string]interface{} `json:"-"`
}

// Item_Meta Computed metadata (creator summary, numChildren, parsed date).
type Item_Meta struct {
	CreatorSummary       *string                `json:"creatorSummary,omitempty"`
	NumChildren          *int                   `json:"numChildren,omitempty"`
	ParsedDate           *string                `json:"parsedDate,omitempty"`
	AdditionalProperties map[string]interface{} `json:"-"`
}

